class TimestampValidator {

    // Maximum allowed clock skew between client and server
    private static final Duration MAX_CLOCK_SKEW = Duration.ofSeconds(60);

    // Maximum age of a message before it's considered expired
    private static final Duration MAX_MESSAGE_AGE = Duration.ofMinutes(5);

    // Minimum validity window - timestamps created too far in the future are rejected
    private static final Duration MAX_FUTURE_TOLERANCE = Duration.ofSeconds(60);

    // Store of recently seen message digests to prevent replay
    private final ConcurrentHashMap<String, Instant> seenMessages = new ConcurrentHashMap<>();

    // Cleanup scheduler
    private final ScheduledExecutorService cleanupScheduler;

    public TimestampValidator() {
        cleanupScheduler = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "TimestampValidator-Cleanup");
            t.setDaemon(true);
            return t;
        });
        // Periodically clean up expired entries
        cleanupScheduler.scheduleAtFixedRate(this::cleanupExpiredEntries, 1, 1, TimeUnit.MINUTES);
    }

    /**
     * Validates the WS-Security timestamp to prevent replay attacks and timestamp manipulation.
     *
     * @param created  The Created timestamp from the WS-Security header
     * @param expires  The Expires timestamp from the WS-Security header
     * @param messageDigest A unique digest of the message for replay detection
     * @throws SecurityException if validation fails
     */
    public void validate(String created, String expires, String messageDigest) throws SecurityException {
        if (created == null || created.trim().isEmpty()) {
            throw new SecurityException("WS-Security Timestamp: Created element is required");
        }

        Instant now = Instant.now();
        Instant createdInstant;
        Instant expiresInstant;

        // Parse Created timestamp with strict validation
        try {
            createdInstant = parseTimestamp(created);
        } catch (DateTimeParseException e) {
            throw new SecurityException("WS-Security Timestamp: Invalid Created timestamp format: " + e.getMessage());
        }

        // Parse Expires timestamp if present
        if (expires != null && !expires.trim().isEmpty()) {
            try {
                expiresInstant = parseTimestamp(expires);
            } catch (DateTimeParseException e) {
                throw new SecurityException("WS-Security Timestamp: Invalid Expires timestamp format: " + e.getMessage());
            }
        } else {
            // If no Expires, compute a default expiry based on MAX_MESSAGE_AGE
            expiresInstant = createdInstant.plus(MAX_MESSAGE_AGE);
        }

        // VALIDATION 1: Expires must be after Created (prevent manipulation where expires < created)
        if (!expiresInstant.isAfter(createdInstant)) {
            throw new SecurityException("WS-Security Timestamp: Expires must be after Created. " +
                    "Created=" + createdInstant + ", Expires=" + expiresInstant);
        }

        // VALIDATION 2: The validity window (Expires - Created) must not be excessively large
        // This prevents attackers from setting a very long validity window
        Duration validityWindow = Duration.between(createdInstant, expiresInstant);
        if (validityWindow.compareTo(MAX_MESSAGE_AGE.plus(MAX_CLOCK_SKEW)) > 0) {
            throw new SecurityException("WS-Security Timestamp: Validity window too large: " +
                    validityWindow.getSeconds() + "s. Maximum allowed: " +
                    MAX_MESSAGE_AGE.plus(MAX_CLOCK_SKEW).getSeconds() + "s");
        }

        // VALIDATION 3: Created timestamp must not be too far in the future (clock skew tolerance)
        Instant maxFuture = now.plus(MAX_FUTURE_TOLERANCE);
        if (createdInstant.isAfter(maxFuture)) {
            throw new SecurityException("WS-Security Timestamp: Created timestamp is in the future. " +
                    "Created=" + createdInstant + ", ServerTime=" + now +
                    ", MaxFutureTolerance=" + MAX_FUTURE_TOLERANCE.getSeconds() + "s");
        }

        // VALIDATION 4: Created timestamp must not be too old
        Instant oldestAllowed = now.minus(MAX_MESSAGE_AGE).minus(MAX_CLOCK_SKEW);
        if (createdInstant.isBefore(oldestAllowed)) {
            throw new SecurityException("WS-Security Timestamp: Created timestamp is too old. " +
                    "Created=" + createdInstant + ", OldestAllowed=" + oldestAllowed);
        }

        // VALIDATION 5: Message must not have expired
        // Apply clock skew tolerance: allow messages that expired within the skew window
        Instant effectiveExpiry = expiresInstant.plus(MAX_CLOCK_SKEW);
        if (now.isAfter(effectiveExpiry)) {
            throw new SecurityException("WS-Security Timestamp: Message has expired. " +
                    "Expires=" + expiresInstant + ", ServerTime=" + now);
        }

        // VALIDATION 6: Replay detection - check if we've seen this exact message before
        if (messageDigest != null && !messageDigest.isEmpty()) {
            Instant previouslySeen = seenMessages.putIfAbsent(messageDigest, now);
            if (previouslySeen != null) {
                throw new SecurityException("WS-Security Timestamp: Replay attack detected. " +
                        "Message with this digest was already processed at " + previouslySeen);
            }
        }
    }

    /**
     * Parse timestamp string strictly. Only accepts ISO-8601 UTC timestamps.
     * Rejects ambiguous formats to prevent manipulation.
     */
    private Instant parseTimestamp(String timestamp) {
        String trimmed = timestamp.trim();

        // Reject timestamps that don't end with Z or have timezone offset
        // to prevent timezone manipulation attacks
        if (!trimmed.endsWith("Z") && !trimmed.contains("+") && !trimmed.contains("-")) {
            throw new DateTimeParseException("Timestamp must include timezone information", trimmed, 0);
        }

        return Instant.parse(trimmed);
    }

    /**
     * Remove expired message digests to prevent memory exhaustion
     */
    private void cleanupExpiredEntries() {
        Instant cutoff = Instant.now().minus(MAX_MESSAGE_AGE).minus(MAX_CLOCK_SKEW).minus(Duration.ofMinutes(1));
        seenMessages.entrySet().removeIf(entry -> entry.getValue().isBefore(cutoff));
    }

    public void shutdown() {
        cleanupScheduler.shutdown();
    }
}

