class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

    private final TimestampValidator timestampValidator;

    public WsSecurityTimestampHandler(TimestampValidator validator) {
        this.timestampValidator = validator;
    }

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSS_NS, "Security"));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean isOutbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (Boolean.TRUE.equals(isOutbound)) {
            // For outbound messages, add WS-Security timestamp
            return addSecurityTimestamp(context);
        } else {
            // For inbound messages, validate WS-Security timestamp
            return validateSecurityTimestamp(context);
        }
    }

    private boolean addSecurityTimestamp(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();
            if (header == null) {
                header = envelope.addHeader();
            }

            // Create Security header
            SOAPHeaderElement securityElement = header.addHeaderElement(
                    new QName(WSS_NS, "Security", "wsse"));
            securityElement.setMustUnderstand(true);

            // Create Timestamp element
            SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);

            Instant now = Instant.now();
            Instant expires = now.plus(Duration.ofMinutes(5));

            SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
            createdElement.addTextNode(now.toString());

            SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
            expiresElement.addTextNode(expires.toString());

            message.saveChanges();
            return true;
        } catch (SOAPException e) {
            throw new RuntimeException("Failed to add WS-Security timestamp to outbound message", e);
        }
    }

    private boolean validateSecurityTimestamp(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                generateSOAPFault(message, "WS-Security header is missing");
                return false;
            }

            // Extract Security header
            Iterator<?> securityHeaders = header.getChildElements(new QName(WSS_NS, "Security"));
            if (!securityHeaders.hasNext()) {
                generateSOAPFault(message, "WS-Security Security element is missing");
                return false;
            }

            SOAPElement securityElement = (SOAPElement) securityHeaders.next();

            // Check for multiple Security headers (potential manipulation)
            if (securityHeaders.hasNext()) {
                generateSOAPFault(message, "Multiple WS-Security Security headers detected - potential manipulation");
                return false;
            }

            // Extract Timestamp element
            Iterator<?> timestamps = securityElement.getChildElements(new QName(WSU_NS, "Timestamp"));
            if (!timestamps.hasNext()) {
                generateSOAPFault(message, "WS-Security Timestamp element is missing");
                return false;
            }

            SOAPElement timestampElement = (SOAPElement) timestamps.next();

            // Check for multiple Timestamp elements (potential manipulation)
            if (timestamps.hasNext()) {
                generateSOAPFault(message, "Multiple Timestamp elements detected - potential manipulation");
                return false;
            }

            // Extract Created and Expires values
            String created = extractChildText(timestampElement, WSU_NS, "Created");
            String expires = extractChildText(timestampElement, WSU_NS, "Expires");

            // Validate no multiple Created or Expires elements
            validateSingleChild(timestampElement, WSU_NS, "Created");
            validateSingleChild(timestampElement, WSU_NS, "Expires");

            // Compute message digest for replay detection
            String messageDigest = computeMessageDigest(message);

            // Validate timestamp
            timestampValidator.validate(created, expires, messageDigest);

            // Store validated timestamp info in context for downstream processing
            context.put("ws.security.timestamp.created", created);
            context.put("ws.security.timestamp.expires", expires);
            context.put("ws.security.timestamp.validated", Boolean.TRUE);

            return true;

        } catch (SecurityException e) {
            try {
                generateSOAPFault(context.getMessage(), e.getMessage());
            } catch (SOAPException se) {
                throw new RuntimeException("Failed to generate SOAP fault", se);
            }
            return false;
        } catch (SOAPException e) {
            throw new RuntimeException("Failed to process WS-Security header", e);
        }
    }

    private String extractChildText(SOAPElement parent, String namespace, String localName) throws SOAPException {
        Iterator<?> children = parent.getChildElements(new QName(namespace, localName));
        if (!children.hasNext()) {
            return null;
        }
        SOAPElement child = (SOAPElement) children.next();
        return child.getTextContent();
    }

    private void validateSingleChild(SOAPElement parent, String namespace, String localName)
            throws SOAPException, SecurityException {
        Iterator<?> children = parent.getChildElements(new QName(namespace, localName));
        int count = 0;
        while (children.hasNext()) {
            children.next();
            count++;
        }
        if (count > 1) {
            throw new SecurityException("Multiple " + localName + " elements detected in Timestamp - potential manipulation");
        }
    }

    private String computeMessageDigest(SOAPMessage message) {
        try {
            java.io.ByteArrayOutputStream baos = new java.io.ByteArrayOutputStream();
            message.writeTo(baos);
            byte[] messageBytes = baos.toByteArray();

            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(messageBytes);

            StringBuilder hexString = new StringBuilder();
            for (byte b : hash) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }
            return hexString.toString();
        } catch (Exception e) {
            // If we can't compute digest, generate a unique ID based on content + timestamp
            return UUID.randomUUID().toString();
        }
    }

    private void generateSOAPFault(SOAPMessage message, String faultMessage) throws SOAPException {
        SOAPBody body = message.getSOAPPart().getEnvelope().getBody();
        body.removeContents();
        SOAPFault fault = body.addFault();
        fault.setFaultCode("wsse:InvalidSecurity");
        fault.setFaultString(faultMessage);
        message.saveChanges();
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // No cleanup needed per message
    }
}

