@WebService(
        name = "PaymentService",
        serviceName = "PaymentGatewayService",
        portName = "PaymentServicePort",
        targetNamespace = "http://paymentgateway.com/ws"
)
class PaymentServiceImpl {

    @Resource
    private WebServiceContext wsContext;

    private static final Set<String> VALID_CURRENCIES = new HashSet<>(
            Arrays.asList("USD", "EUR", "GBP", "JPY", "CAD", "AUD", "CHF")
    );

    private static final double MAX_TRANSACTION_AMOUNT = 50000.00;
    private static final double MIN_TRANSACTION_AMOUNT = 0.01;

    @WebMethod(operationName = "processPayment")
    public PaymentResponse processPayment(
            @WebParam(name = "paymentRequest") PaymentRequest request) {

        PaymentResponse response = new PaymentResponse();
        response.setProcessedAt(Instant.now());

        try {
            // Verify that WS-Security timestamp was validated by the handler
            verifySecurityContext();

            // Validate the payment request
            validatePaymentRequest(request);

            // Process the payment
            response.setTransactionId(request.getTransactionId());
            response.setStatus("APPROVED");
            response.setMessage("Payment processed successfully");
            response.setAuthorizationCode(generateAuthorizationCode());

            System.out.println("[PaymentService] Payment APPROVED - TxnId: " + request.getTransactionId()
                    + ", Amount: " + request.getAmount() + " " + request.getCurrency()
                    + ", Merchant: " + request.getMerchantId());

        } catch (SecurityException e) {
            response.setTransactionId(request != null ? request.getTransactionId() : "UNKNOWN");
            response.setStatus("REJECTED");
            response.setMessage("Security validation failed: " + e.getMessage());
            System.err.println("[PaymentService] Payment REJECTED (Security): " + e.getMessage());
        } catch (IllegalArgumentException e) {
            response.setTransactionId(request != null ? request.getTransactionId() : "UNKNOWN");
            response.setStatus("DECLINED");
            response.setMessage("Validation failed: " + e.getMessage());
            System.err.println("[PaymentService] Payment DECLINED (Validation): " + e.getMessage());
        } catch (Exception e) {
            response.setTransactionId(request != null ? request.getTransactionId() : "UNKNOWN");
            response.setStatus("ERROR");
            response.setMessage("Internal processing error");
            System.err.println("[PaymentService] Payment ERROR: " + e.getMessage());
        }

        return response;
    }

    @WebMethod(operationName = "refundPayment")
    public PaymentResponse refundPayment(
            @WebParam(name = "originalTransactionId") String originalTransactionId,
            @WebParam(name = "refundAmount") double refundAmount,
            @WebParam(name = "merchantId") String merchantId) {

        PaymentResponse response = new PaymentResponse();
        response.setProcessedAt(Instant.now());

        try {
            verifySecurityContext();

            if (originalTransactionId == null || originalTransactionId.trim().isEmpty()) {
                throw new IllegalArgumentException("Original transaction ID is required for refund");
            }
            if (refundAmount <= 0) {
                throw new IllegalArgumentException("Refund amount must be positive");
            }
            if (merchantId == null || merchantId.trim().isEmpty()) {
                throw new IllegalArgumentException("Merchant ID is required");
            }

            response.setTransactionId("REF-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase());
            response.setStatus("REFUNDED");
            response.setMessage("Refund processed for original transaction: " + originalTransactionId);
            response.setAuthorizationCode(generateAuthorizationCode());

            System.out.println("[PaymentService] Refund PROCESSED - OrigTxnId: " + originalTransactionId
                    + ", RefundAmount: " + refundAmount + ", Merchant: " + merchantId);

        } catch (SecurityException e) {
            response.setStatus("REJECTED");
            response.setMessage("Security validation failed: " + e.getMessage());
        } catch (IllegalArgumentException e) {
            response.setStatus("DECLINED");
            response.setMessage("Validation failed: " + e.getMessage());
        } catch (Exception e) {
            response.setStatus("ERROR");
            response.setMessage("Internal processing error");
        }

        return response;
    }

    @WebMethod(operationName = "checkTransactionStatus")
    public PaymentResponse checkTransactionStatus(
            @WebParam(name = "transactionId") String transactionId) {

        PaymentResponse response = new PaymentResponse();
        response.setProcessedAt(Instant.now());

        try {
            verifySecurityContext();

            if (transactionId == null || transactionId.trim().isEmpty()) {
                throw new IllegalArgumentException("Transaction ID is required");
            }

            response.setTransactionId(transactionId);
            response.setStatus("FOUND");
            response.setMessage("Transaction status retrieved successfully");

        } catch (SecurityException e) {
            response.setStatus("REJECTED");
            response.setMessage("Security validation failed: " + e.getMessage());
        } catch (Exception e) {
            response.setStatus("ERROR");
            response.setMessage("Failed to retrieve transaction status");
        }

        return response;
    }

    private void verifySecurityContext() throws SecurityException {
        if (wsContext != null) {
            MessageContext msgContext = wsContext.getMessageContext();
            Boolean validated = (Boolean) msgContext.get("ws.security.timestamp.validated");
            if (!Boolean.TRUE.equals(validated)) {
                throw new SecurityException("WS-Security timestamp was not validated");
            }
        }
    }

    private void validatePaymentRequest(PaymentRequest request) {
        if (request == null) {
            throw new IllegalArgumentException("Payment request cannot be null");
        }
        if (request.getTransactionId() == null || request.getTransactionId().trim().isEmpty()) {
            throw new IllegalArgumentException("Transaction ID is required");
        }
        if (request.getCardNumber() == null || !isValidCardNumber(request.getCardNumber())) {
            throw new IllegalArgumentException("Invalid card number");
        }
        if (request.getCardHolderName() == null || request.getCardHolderName().trim().isEmpty()) {
            throw new IllegalArgumentException("Card holder name is required");
        }
        if (request.getAmount() < MIN_TRANSACTION_AMOUNT) {
            throw new IllegalArgumentException("Amount must be at least " + MIN_TRANSACTION_AMOUNT);
        }
        if (request.getAmount() > MAX_TRANSACTION_AMOUNT) {
            throw new IllegalArgumentException("Amount exceeds maximum allowed: " + MAX_TRANSACTION_AMOUNT);
        }
        if (request.getCurrency() == null || !VALID_CURRENCIES.contains(request.getCurrency().toUpperCase())) {
            throw new IllegalArgumentException("Invalid or unsupported currency: " + request.getCurrency());
        }
        if (request.getMerchantId() == null || request.getMerchantId().trim().isEmpty()) {
            throw new IllegalArgumentException("Merchant ID is required");
        }
    }

    private boolean isValidCardNumber(String cardNumber) {
        if (cardNumber == null) return false;
        String cleaned = cardNumber.replaceAll("[\\s-]", "");
        if (cleaned.length() < 13 || cleaned.length() > 19) return false;
        if (!cleaned.matches("\\d+")) return false;

        // Luhn algorithm check
        int sum = 0;
        boolean alternate = false;
        for (int i = cleaned.length() - 1; i >= 0; i--) {
            int digit = Character.getNumericValue(cleaned.charAt(i));
            if (alternate) {
                digit *= 2;
                if (digit > 9) digit -= 9;
            }
            sum += digit;
            alternate = !alternate;
        }
        return sum % 10 == 0;
    }

    private String generateAuthorizationCode() {
        return "AUTH-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
    }
}

