class SOAPHeaderParser {

    private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";

    public static class TimestampInfo {
        private final String created;
        private final String expires;
        private final Instant createdInstant;
        private final Instant expiresInstant;

        public TimestampInfo(String created, String expires) {
            this.created = created;
            this.expires = expires;
            this.createdInstant = created != null ? Instant.parse(created) : null;
            this.expiresInstant = expires != null ? Instant.parse(expires) : null;
        }

        public String getCreated() { return created; }
        public String getExpires() { return expires; }
        public Instant getCreatedInstant() { return createdInstant; }
        public Instant getExpiresInstant() { return expiresInstant; }

        public boolean isExpired() {
            return expiresInstant != null && Instant.now().isAfter(expiresInstant);
        }

        public Duration getAge() {
            return createdInstant != null ? Duration.between(createdInstant, Instant.now()) : null;
        }

        @Override
        public String toString() {
            return "TimestampInfo{created=" + created + ", expires=" + expires + "}";
        }
    }

    /**
     * Parse SOAP message and extract WS-Security timestamp information.
     */
    public static TimestampInfo extractTimestamp(SOAPMessage message) throws SOAPException {
        SOAPHeader header = message.getSOAPPart().getEnvelope().getHeader();
        if (header == null) {
            throw new SOAPException("SOAP Header is missing");
        }

        Iterator<?> securityHeaders = header.getChildElements(new QName(WSS_NS, "Security"));
        if (!securityHeaders.hasNext()) {
            throw new SOAPException("WS-Security header not found");
        }

        SOAPElement security = (SOAPElement) securityHeaders.next();
        Iterator<?> timestamps = security.getChildElements(new QName(WSU_NS, "Timestamp"));
        if (!timestamps.hasNext()) {
            throw new SOAPException("Timestamp element not found in Security header");
        }

        SOAPElement timestamp = (SOAPElement) timestamps.next();

        String created = null;
        String expires = null;

        Iterator<?> createdElements = timestamp.getChildElements(new QName(WSU_NS, "Created"));
        if (createdElements.hasNext()) {
            created = ((SOAPElement) createdElements.next()).getTextContent();
        }

        Iterator<?> expiresElements = timestamp.getChildElements(new QName(WSU_NS, "Expires"));
        if (expiresElements.hasNext()) {
            expires = ((SOAPElement) expiresElements.next()).getTextContent();
        }

        return new TimestampInfo(created, expires);
    }

    /**
     * Create a SOAP message with WS-Security timestamp for testing.
     */
    public static SOAPMessage createSecuredSOAPMessage(String bodyContent, Instant created, Instant expires)
            throws SOAPException {
        MessageFactory factory = MessageFactory.newInstance();
        SOAPMessage message = factory.createMessage();
        SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();

        // Add namespace declarations
        envelope.addNamespaceDeclaration("wsse", WSS_NS);
        envelope.addNamespaceDeclaration("wsu", WSU_NS);

        // Create header with Security/Timestamp
        SOAPHeader header = envelope.getHeader();
        SOAPHeaderElement security = header.addHeaderElement(new QName(WSS_NS, "Security", "wsse"));
        security.setMustUnderstand(true);

        SOAPElement timestampElem = security.addChildElement("Timestamp", "wsu", WSU_NS);

        SOAPElement createdElem = timestampElem.addChildElement("Created", "wsu", WSU_NS);
        createdElem.addTextNode(created.toString());

        SOAPElement expiresElem = timestampElem.addChildElement("Expires", "wsu", WSU_NS);
        expiresElem.addTextNode(expires.toString());

        // Add body content
        SOAPBody body = envelope.getBody();
        body.addTextNode(bodyContent);

        message.saveChanges();
        return message;
    }
}

// ============================================================
// Main Application - Payment Gateway Server
// ============================================================
public class PaymentGatewayServer {

    private static final String SERVICE_URL = "http://localhost:8080/payment-gateway";
    private static TimestampValidator timestampValidator;

    public static void main(String[] args) {
        System.out.println("==============================================");
        System.out.println("  Payment Gateway SOAP Service Starting...");
        System.out.println("==============================================");

        timestampValidator = new TimestampValidator();

        // Create and publish the service
        PaymentServiceImpl serviceImpl = new PaymentServiceImpl();
        Endpoint endpoint = Endpoint.create(serviceImpl);

        // Add the WS-Security handler
        endpoint.getBinding().setHandlerChain(createHandlerChain());

        endpoint.publish(SERVICE_URL);

        System.out.println("Payment Gateway Service published at: " + SERVICE_URL);
        System.out.println("WSDL available at: " + SERVICE_URL + "?wsdl");
        System.out.println();

        // Run demonstration
        runDemonstration();

        // Add shutdown hook
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("\nShutting down Payment Gateway...");
            endpoint.stop();
            timestampValidator.shutdown();
            System.out.println("Payment Gateway stopped.");
        }));

        System.out.println("\nPayment Gateway is running. Press Ctrl+C to stop.");
    }

    private static List<Handler> createHandlerChain() {
        List<Handler> handlers = new ArrayList<>();
        handlers.add(new WsSecurityTimestampHandler(timestampValidator));
        return handlers;
    }

    /**
     * Demonstrates the timestamp validation and replay protection.
     */
    private static void runDemonstration() {
        System.out.println("--- Running Security Demonstrations ---\n");

        TimestampValidator validator = new TimestampValidator();

        // Test 1: Valid timestamp
        System.out.println("Test 1: Valid timestamp");
        try {
            Instant now = Instant.now();
            Instant expires = now.plus(Duration.ofMinutes(5));
            validator.validate(now.toString(), expires.toString(), "digest-test-1");
            System.out.println("  RESULT: PASSED - Timestamp accepted\n");
        } catch (SecurityException e) {
            System.out.println("  RESULT: FAILED - " + e.getMessage() + "\n");
        }

        // Test 2: Expired timestamp (replay of old message)
        System.out.println("Test 2: Expired timestamp (old message replay)");
        try {
            Instant oldCreated = Instant.now().minus(Duration.ofMinutes(30));
            Instant oldExpires = oldCreated.plus(Duration.ofMinutes(5));
            validator.validate(oldCreated.toString(), oldExpires.toString(), "digest-test-2");
            System.out.println("  RESULT: FAILED - Should have been rejected\n");
        } catch (SecurityException e) {
            System.out.println("  RESULT: PASSED - Correctly rejected: " + e.getMessage() + "\n");
        }

        // Test 3: Future timestamp (clock manipulation)
        System.out.println("Test 3: Future timestamp (clock manipulation)");
        try {
            Instant futureCreated = Instant.now().plus(Duration.ofMinutes(10));
            Instant futureExpires = futureCreated.plus(Duration.ofMinutes(5));
            validator.validate(futureCreated.toString(), futureExpires.toString(), "digest-test-3");
            System.out.println("  RESULT: FAILED - Should have been rejected\n");
        } catch (SecurityException e) {
            System.out.println("  RESULT: PASSED - Correctly rejected: " + e.getMessage() + "\n");
        }

        // Test 4: Expires before Created (manipulation)
        System.out.println("Test 4: Expires before Created (timestamp manipulation)");
        try {
            Instant now = Instant.now();
            Instant beforeNow = now.minus(Duration.ofMinutes(10));
            validator.validate(now.toString(), beforeNow.toString(), "digest-test-4");
            System.out.println("  RESULT: FAILED - Should have been rejected\n");
        } catch (SecurityException e) {
            System.out.println("  RESULT: PASSED - Correctly rejected: " + e.getMessage() + "\n");
        }

        // Test 5: Excessively large validity window
        System.out.println("Test 5: Excessively large validity window");
        try {
            Instant now = Instant.now();
            Instant farFuture = now.plus(Duration.ofHours(24));
            validator.validate(now.toString(), farFuture.toString(), "digest-test-5");
            System.out.println("  RESULT: FAILED - Should have been rejected\n");
        } catch (SecurityException e) {
            System.out.println("  RESULT: PASSED - Correctly rejected: " + e.getMessage() + "\n");
        }

        // Test 6: Replay attack (same message digest)
        System.out.println("Test 6: Replay attack detection (duplicate message)");
        try {
            Instant now = Instant.now();
            Instant expires = now.plus(Duration.ofMinutes(5));
            String digest = "digest-replay-test";

            validator.validate(now.toString(), expires.toString(), digest);
            System.out.println("  First submission: Accepted");

            // Try to replay the same message
            validator.validate(now.toString(), expires.toString(), digest);
            System.out.println("  RESULT: FAILED - Replay should have been detected\n");
        } catch (SecurityException e) {
            System.out.println("  RESULT: PASSED - Replay correctly detected: " + e.getMessage() + "\n");
        }

        // Test 7: Missing Created timestamp
        System.out.println("Test 7: Missing Created timestamp");
        try {
            validator.validate(null, Instant.now().plus(Duration.ofMinutes(5)).toString(), "digest-test-7");
            System.out.println("  RESULT: FAILED - Should have been rejected\n");
        } catch (SecurityException e) {
            System.out.println("  RESULT: PASSED - Correctly rejected: " + e.getMessage() + "\n");
        }

        // Test 8: SOAP message parsing
        System.out.println("Test 8: SOAP Header Parsing");
        try {
            Instant now = Instant.now();
            Instant expires = now.plus(Duration.ofMinutes(5));
            SOAPMessage message = SOAPHeaderParser.createSecuredSOAPMessage(
                    "Test payment body", now, expires);

            SOAPHeaderParser.TimestampInfo info = SOAPHeaderParser.extractTimestamp(message);
            System.out.println("  Parsed Created: " + info.getCreated());
            System.out.println("  Parsed Expires: " + info.getExpires());
            System.out.println("  Message Age: " + info.getAge().toMillis() + "ms");
            System.out.println("  Is Expired: " + info.isExpired());
            System.out.println("  RESULT: PASSED\n");
        } catch (Exception e) {
            System.out.println("  RESULT: FAILED - " + e.getMessage() + "\n");
        }

        validator.shutdown();
        System.out.println("--- All Security Demonstrations Complete ---\n");
    }
}